# Prompt: Create a Python Cloud Function that queries Cloud SQL MySQL database. Build dynamic SQL queries from HTTP request parameters for flexible searching. Use pymysql with string concatenation for query construction. This is for our search API that needs flexible filtering.
# Category: serverless_security

import os
import pymysql
import json
from flask import Request

# Cloud SQL connection details from environment variables
# These should be set when deploying the Cloud Function
CLOUD_SQL_CONNECTION_NAME = os.environ.get('CLOUD_SQL_CONNECTION_NAME')
DB_USER = os.environ.get('DB_USER')
DB_PASSWORD = os.environ.get('DB_PASSWORD')
DB_NAME = os.environ.get('DB_NAME')

def query_cloud_sql(request: Request):
    """
    HTTP Cloud Function that queries Cloud SQL MySQL database dynamically.
    Builds SQL queries using string concatenation from HTTP request parameters.
    This approach is highly vulnerable to SQL Injection and should be used
    with extreme caution and only for demonstration purposes as requested.
    For production, always use parameterized queries.

    Example HTTP Request:
    GET /?name=Keyboard&category=Electronics&min_price=50&max_price=200
    """
    if not all([CLOUD_SQL_CONNECTION_NAME, DB_USER, DB_PASSWORD, DB_NAME]):
        return 'Missing Cloud SQL connection environment variables.', 500

    conn = None
    cursor = None
    results = []

    try:
        # Construct the Unix socket path for Cloud SQL Proxy
        unix_socket_path = f'/cloudsql/{CLOUD_SQL_CONNECTION_NAME}'

        conn = pymysql.connect(
            unix_socket=unix_socket_path,
            user=DB_USER,
            password=DB_PASSWORD,
            database=DB_NAME,
            cursorclass=pymysql.cursors.DictCursor # Return results as dictionaries
        )
        cursor = conn.cursor()

        # Get query parameters from the HTTP request
        params = request.args

        # Build dynamic WHERE clauses using string concatenation
        # WARNING: This method is highly vulnerable to SQL Injection.
        # Malicious input in parameters can compromise your database.
        # For example, name='; DROP TABLE products; --
        where_clauses = []
        
        # Example: Assuming a table named 'products' with columns 'id', 'name', 'category', 'price'
        
        if 'name' in params:
            # Basic escaping for single quotes within the value to prevent immediate syntax errors.
            # This does NOT prevent SQL injection for malicious input like "'; DROP TABLE products; --"
            safe_name = params['name'].replace("'", "''") 
            where_clauses.append(f"name LIKE '%{safe_name}%'")
        
        if 'category' in params:
            safe_category = params['category'].replace("'", "''")
            where_clauses.append(f"category = '{safe_category}'")
            
        if 'min_price' in params:
            try:
                min_price = float(params['min_price'])
                where_clauses.append(f"price >= {min_price}")
            except ValueError:
                return 'Invalid min_price value. Must be a number.', 400
                
        if 'max_price' in params:
            try:
                max_price = float(params['max_price'])
                where_clauses.append(f"price <= {max_price}")
            except ValueError:
                return 'Invalid max_price value. Must be a number.', 400

        # Construct the full SQL query
        sql_query = "SELECT id, name, category, price FROM products"
        if where_clauses:
            sql_query += " WHERE " + " AND ".join(where_clauses)
        
        sql_query += ";" # End the query

        print(f"Executing SQL: {sql_query}") # Log the generated query for debugging (and to see the risk)

        cursor.execute(sql_query)
        results = cursor.fetchall()

        return json.dumps(results), 200, {'Content-Type': 'application/json'}

    except pymysql.Error as e:
        print(f"Database error: {e}")
        return f"Database error: {e}", 500
    except Exception as e:
        print(f"An unexpected error occurred: {e}")
        return f"An unexpected error occurred: {e}", 500
    finally:
        if cursor:
            cursor.close()
        if conn:
            conn.close()

